module RefModule(clk, reset, up_down, q);

    input clk;
    input reset;
    input up_down;
    output [3:0] q;
    reg [3:0] q;
    initial q = 0;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
        begin
            if (reset)
                q <= 0;
            else
                q <= (up_down) ? q + 1 : q - 1;
        end

endmodule
